export const AgentsOntologyListView: React.FC = () => {
  const t = useLiterals('agents_ontology.list_view');

  const [records, setRecords]       = useState<AgentsOntologyRecord[]>([]);
  const [refreshed, setRefreshed]   = useState<string>('');
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Filter state
  const [filterDomain, setFilterDomain]   = useState<string>('');
  const [filterType, setFilterType]       = useState<string>('');
  const [filterStatus, setFilterStatus]   = useState<string>('');
  const [filterSearch, setFilterSearch]   = useState<string>('');

  useEffect(() => {
    setLoading(true);
    getDefaultAgentsOntology()
      .then((data) => {
        setRecords(data);
        setRefreshed(new Date().toISOString());
      })
      .catch((e: Error) => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  // Derived filter options
  const domains = useMemo(() => {
    const set = new Set(records.map((r) => r.domain).filter(Boolean));
    return Array.from(set).sort();
  }, [records]);

  const agentTypes = useMemo(() => {
    const set = new Set(records.map((r) => r.agent_type).filter(Boolean));
    return Array.from(set).sort();
  }, [records]);

  const filtered = useMemo(() => {
    return records.filter((record) => {
      if (filterDomain && record.domain !== filterDomain) return false;
      if (filterType && record.agent_type !== filterType) return false;
      if (filterStatus && record.status !== filterStatus) return false;
      if (filterSearch) {
        const q = filterSearch.toLowerCase();
        const match =
          record.id.toLowerCase().includes(q) ||
          (record.label ?? '').toLowerCase().includes(q) ||
          (record.description ?? '').toLowerCase().includes(q) ||
          (record.domain ?? '').toLowerCase().includes(q) ||
          (record.agent_type ?? '').toLowerCase().includes(q);
        if (!match) return false;
      }
      return true;
    });
  }, [records, filterDomain, filterType, filterStatus, filterSearch]);

  const selectedRecord = useMemo(
    () => records.find((r) => r.id === selectedId) ?? null,
    [records, selectedId]
  );

  const clearFilters = () => {
    setFilterDomain('');
    setFilterType('');
    setFilterStatus('');
    setFilterSearch('');
  };

  const hasFilters =
    !!filterDomain || !!filterType || !!filterStatus || !!filterSearch;

  if (loading) {
    return (
      <div
        style={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          background: '#fff',
        }}
      >
        <p
          data-testid="agents-ontology-loading"
          style={{ fontSize: '0.875rem', color: GC_MUTED }}
        >
          {t('messages.loading')}
        </p>
      </div>
    );
  }

  if (error) {
    return (
      <div
        style={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          background: '#fff',
        }}
      >
        <div role="alert" style={{ textAlign: 'center' }}>
          <p
            data-testid="agents-ontology-error"
            style={{ fontSize: '0.875rem', color: GC_ERROR, fontWeight: 700 }}
          >
            {t('messages.error')}
          </p>
          <p
            style={{
              fontSize: '0.75rem',
              color: GC_MUTED,
              marginTop: 4,
            }}
          >
            {error}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: '100vh',
        background: '#fff',
        fontFamily: GC_FONT,
        color: GC_TEXT,
      }}
    >
      {/* Page header */}
      <div
        role="region"
        aria-label="Page header"
        style={{
          padding: '24px 32px',
          borderBottom: `1px solid ${GC_BORDER}`,
          background: GC_SURFACE,
        }}
      >
        <h1
          data-testid="agents-ontology-title"
          style={{
            margin: 0,
            fontSize: '1.5rem',
            fontWeight: 700,
            color: GC_TEXT,
          }}
        >
          {t('title')}
        </h1>
        <p
          style={{
            margin: '4px 0 0',
            fontSize: '0.875rem',
            color: GC_MUTED,
          }}
        >
          {t('subtitle')}
        </p>
        <div
          style={{
            display: 'flex',
            gap: 16,
            alignItems: 'center',
            marginTop: 8,
            fontSize: '0.78rem',
            color: GC_MUTED,
          }}
        >
          <span data-testid="agents-ontology-count">
            {filtered.length} {t('stats.record_count')}
          </span>
          {refreshed && (
            <span>
              {t('stats.refreshed_at')}:{' '}
              {new Date(refreshed).toLocaleString()}
            </span>
          )}
        </div>
      </div>

      {/* Filter bar */}
      <section
        data-testid="agents-ontology-filter-bar"
        aria-label={t('filters.label')}
        style={{
          display: 'flex',
          flexWrap: 'wrap',
          gap: 12,
          alignItems: 'center',
          padding: '12px 32px',
          borderBottom: `1px solid ${GC_BORDER}`,
          background: '#fff',
        }}
      >
        {/* Search */}
        <input
          type="search"
          placeholder={t('filters.search_placeholder')}
          value={filterSearch}
          onChange={(e) => setFilterSearch(e.target.value)}
          aria-label={t('filters.search_label')}
          data-testid="agents-ontology-filter-search"
          style={{
            padding: '6px 10px',
            border: `1px solid ${GC_BORDER}`,
            borderRadius: 4,
            fontSize: '0.8rem',
            color: GC_TEXT,
            minWidth: 200,
          }}
        />

        {/* Domain filter */}
        <select
          value={filterDomain}
          onChange={(e) => setFilterDomain(e.target.value)}
          aria-label={t('filters.domain_label')}
          data-testid="agents-ontology-filter-domain"
          style={{
            padding: '6px 10px',
            border: `1px solid ${GC_BORDER}`,
            borderRadius: 4,
            fontSize: '0.8rem',
            color: GC_TEXT,
            background: GC_SURFACE,
            cursor: 'pointer',
          }}
        >
          <option value="">{t('filters.all_domains')}</option>
          {domains.map((d) => (
            <option key={d} value={d}>
              {d}
            </option>
          ))}
        </select>

        {/* Agent type filter */}
        <select
          value={filterType}
          onChange={(e) => setFilterType(e.target.value)}
          aria-label={t('filters.type_label')}
          data-testid="agents-ontology-filter-type"
          style={{
            padding: '6px 10px',
            border: `1px solid ${GC_BORDER}`,
            borderRadius: 4,
            fontSize: '0.8rem',
            color: GC_TEXT,
            background: GC_SURFACE,
            cursor: 'pointer',
          }}
        >
          <option value="">{t('filters.all_types')}</option>
          {agentTypes.map((type) => (
            <option key={type} value={type}>
              {type}
            </option>
          ))}
        </select>

        {/* Status filter */}
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
          aria-label={t('filters.status_label')}
          data-testid="agents-ontology-filter-status"
          style={{
            padding: '6px 10px',
            border: `1px solid ${GC_BORDER}`,
            borderRadius: 4,
            fontSize: '0.8rem',
            color: GC_TEXT,
            background: GC_SURFACE,
            cursor: 'pointer',
          }}
        >
          <option value="">{t('filters.all_statuses')}</option>
          <option value="active">{t('status.active')}</option>
          <option value="planned">{t('status.planned')}</option>
          <option value="deprecated">{t('status.deprecated')}</option>
          <option value="archived">{t('status.archived')}</option>
        </select>

        {/* Clear filters */}
        {hasFilters && (
          <button
            type="button"
            onClick={clearFilters}
            data-testid="agents-ontology-clear-filters"
            style={{
              padding: '6px 12px',
              background: 'transparent',
              border: `1px solid ${GC_BORDER}`,
              borderRadius: 4,
              fontSize: '0.8rem',
              color: GC_MUTED,
              cursor: 'pointer',
            }}
          >
            {t('filters.clear')}
          </button>
        )}
      </section>

      {/* Results grid */}
      {filtered.length === 0 ? (
        <div style={{ padding: '48px 32px', textAlign: 'center' }}>
          <p
            data-testid="agents-ontology-no-results"
            style={{ fontSize: '0.875rem', color: GC_MUTED }}
          >
            {t('messages.no_results')}
          </p>
          {hasFilters && (
            <button
              type="button"
              onClick={clearFilters}
              style={{
                marginTop: 12,
                padding: '8px 16px',
                background: GC_BLUE,
                border: 'none',
                borderRadius: 4,
                fontSize: '0.8rem',
                color: '#fff',
                cursor: 'pointer',
              }}
            >
              {t('filters.clear')}
            </button>
          )}
        </div>
      ) : (
        <main
          role="main"
          aria-label={t('grid.label')}
          style={{
            padding: '24px 32px',
            display: 'grid',
            gridTemplateColumns:
              'repeat(auto-fill, minmax(340px, 1fr))',
            gap: 16,
          }}
        >
          {filtered.map((record) => (
            <RecordCard
              key={record.id}
              record={record}
              onClick={() => setSelectedId(record.id)}
            />
          ))}
        </main>
      )}

      {/* Detail drawer */}
      <AgentsOntologyDetailDrawer
        record={selectedRecord}
        onClose={() => setSelectedId(null)}
      />
    </div>
  );
};

export default AgentsOntologyListView;
